"use strict";document.addEventListener("DOMContentLoaded",function(){const t=document.getElementById("logoutLink");t&&t.addEventListener("click",function(e){e.preventDefault();const o=t.dataset.logoutUrl,n=t.dataset.csrfToken||t.dataset.csrfToken;fetch(o,{method:"POST",headers:{"X-CSRFToken":n}}).then(c=>{c.ok?window.location.reload():window.location.href="/"}).catch(()=>{window.location.href="/"})})});
